args.sparql:
SELECT ?chair ?birthDate WHERE {
  ?committee wdt:P31 wd:Q8313874;
             rdfs:label "Accountability & Reform Committee"@en.
  ?committee wdt:P179 ?chair.
  ?chair wdt:P569 ?birthDate.
  FILTER(LANG(?birthDate) = 'en')
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?chair ?birthDate WHERE {
  ?committee wdt:P31 wd:Q8313874;
             rdfs:label "Accountability and Reform Committee"@en.
  ?chair p:P39 ?committeeStatement.
  ?committeeStatement ps:P39 ?committee;
                 pq:P544 wd:Q17776723.
  ?chair wdt:P569 ?birthDate.
}

